- (__kindof UICollectionViewCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    CountDownCollectionCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"cell" forIndexPath:indexPath];

    [_CountDowns[indexPath.item] updateRemainingDays];

    cell.icon.image = [UIImage imageNamed:@"A_CountDown_icon"];

    cell.nameLabel.text = _CountDowns[indexPath.item].Title;

    NSDateFormatter *formatter = [[NSDateFormatter alloc] init];
    formatter.dateFormat = @"'Target date: 'yyyy-MM-dd";
    NSDate *targetDate = _CountDowns[indexPath.item].TargetDate;
    NSString *dateString = [formatter stringFromDate:targetDate];
    cell.dateLabel.text = dateString;

    NSComparisonResult result = [_CountDowns[indexPath.item] CompareDaysResult];
    cell.dayCount = _CountDowns[indexPath.item].RemainingDays;
    if (result == NSOrderedAscending) {
        cell.timeView.days.text = [NSString stringWithFormat:@"%ld days have passed", cell.dayCount];
    }  else {
        cell.timeView.days.text = [NSString stringWithFormat:@"There are still %ld days left", cell.dayCount];
    }




    if (self.isDelete) {
        cell.deleteButton.hidden = NO;
//        cell.timeView.hidden = YES;
//        cell.userInteractionEnabled = NO;
        cell.userInteractionEnabled = YES;
        cell.deleteButton.userInteractionEnabled = YES;
    } else {
        cell.deleteButton.hidden = YES;
//        cell.timeView.hidden = NO;
        cell.userInteractionEnabled = YES;
    }
    cell.deleteButton.tag = indexPath.item;
    [cell.deleteButton addTarget:self action:@selector(deleteCountDown:) forControlEvents:UIControlEventTouchUpInside];

//    cell.layer.borderColor = DEEP_COLOR.CGColor;
//    cell.layer.borderWidth = ZOOM(1);

    NSLog(@"cell.dayCount的值为：%ld", cell.dayCount);
    NSLog(@"RemainingDays的值为：%ld", _CountDowns[indexPath.item].RemainingDays);

    return cell;
}

