- (void)deleteCountDown:(UIButton *)sender {

    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Delete"
                                                                   message:@"Are you sure to delete?"
                                                            preferredStyle:UIAlertControllerStyleAlert];
    [alert addAction:[UIAlertAction actionWithTitle:@"Cancel" style:UIAlertActionStyleDefault handler:nil]];
    [alert addAction:[UIAlertAction actionWithTitle:@"Confirm" style:UIAlertActionStyleDestructive handler:^(UIAlertAction * _Nonnull action){
        dispatch_async(dispatch_get_main_queue(), ^{
            // 检查indexPath是否有效
            if (sender.tag >= self.CountDowns.count) {
                return;
            }
            NSInteger a = self.CountDowns.count;
            NSInteger b = sender.tag;
            // 直接获取要删除的账号
            CountDownModel *deleteCountDown = self.CountDowns[sender.tag];

            // 从数据源中移除
            [self.CountDowns removeObjectAtIndex:sender.tag];
            [CountDownModel.CountDowns removeObject:deleteCountDown];
            [CountDownModel save];

            a = self.CountDowns.count;
            b = sender.tag;

            [self.collectionView reloadData];
        });
        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
            [SVProgressHUD dismiss];
            // 保存成功，弹出成功的hud
            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.1 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
                [UIView showHUDWithStatus:NSLocalizedString(@"Delete Successful", nil) imageName:@"Success"];

            });
        });
    }]];
    [self presentViewController:alert animated:YES completion:nil];

}

