@implementation MemoViewController

- (instancetype)init {
    self = [super init];
    if (self) {
        self.view.backgroundColor = BACKGROUND_COLOR;
        self.modalPresentationStyle = UIModalPresentationFullScreen;

    }
    return self;
}

- (void)viewDidLoad {
    [super viewDidLoad];
    [self setupUI];
    [self loadData];

    [[NSNotificationCenter defaultCenter] addObserver:self selector:@selector(handleMemoUpdate) name:@"MemoDataUpdated" object:nil];
}
- (void)viewWillAppear:(BOOL)animated {
    [super viewWillAppear:animated];
    [self loadData];

}


- (void)dealloc {
    [[NSNotificationCenter defaultCenter] removeObserver:self];
}

- (void)setupUI {

    self.view.backgroundColor = [UIColor colorWithRed:0.95 green:0.95 blue:0.95 alpha:1.0];

    // 设置导航栏
    [self setupNavigationBar];

    // 搜索栏
    [self setupSearchBar];

    // 集合视图
    [self.view addSubview:self.collectionView];

    // 空状态提示
    [self.view addSubview:self.emptyLabel];

    [self.view addSubview:self.addButton];

    [self setupConstraints];

    self.collectionView.keyboardDismissMode = UIScrollViewKeyboardDismissModeOnDrag;
    self.addButton.hidden = self.displayMemos.count > 0;
}

- (void)setupNavigationBar {
    UIBarButtonItem *editButton = [[UIBarButtonItem alloc] initWithImage:[UIImage imageNamed:@"A_AddButton"]
                                                                   style:UIBarButtonItemStylePlain
                                                                  target:self
                                                                  action:@selector(addNewMemo)];
    UIBarButtonItem *deleteButton = [[UIBarButtonItem alloc] initWithImage:[UIImage imageNamed:@"A_deleteButton"]
                                                                   style:UIBarButtonItemStylePlain
                                                                  target:self
                                                                  action:@selector(toggleEditMode)];
    editButton.tintColor = BLACK_COLOR;
    deleteButton.tintColor = BLACK_COLOR;
    self.navigationItem.rightBarButtonItems = @[editButton, deleteButton];
}

- (void)setupSearchBar {
    UIView *BackView = [[UIView alloc] init];
    BackView.layer.cornerRadius = ZOOM(24);
    BackView.backgroundColor = WHITE_COLOR;
    self.searchBar = [[UISearchBar alloc] init];
    self.searchBar.placeholder = @"Search";
    self.searchBar.delegate = self;
    self.searchBar.backgroundImage = [[UIImage alloc] init]; // 去除背景
    self.searchButton = [[UIButton alloc] init];
    [self.searchButton setImage:[UIImage imageNamed:@"A_search"] forState:UIControlStateNormal];
//    [self.searchButton setTitle:@"搜索" forState:UIControlStateNormal];
//    [self.searchButton setTitleColor:BLACK_COLOR forState:UIControlStateNormal];
    self.searchButton.titleLabel.font = [UIFont systemFontOfSize:16];
    UITextField *searchField = self.searchBar.searchTextField;
    if (searchField) {
        // 修改文本框背景色
        searchField.backgroundColor = CLEAR_COLOR;
    }
    [self.view addSubview:BackView];
    [self.view addSubview:self.searchButton];

    [BackView mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.view.mas_safeAreaLayoutGuideTop).offset(ZOOMW(16));
        make.left.equalTo(self.view).offset(ZOOMW(16));
        make.right.equalTo(self.view).offset(ZOOMW(-16));
