    }];
}

- (void)loadData {
    self.displayMemos = [MemoModel allMemos];
    [self.collectionView reloadData];
    [self updateEmptyState];

}

- (void)updateEmptyState {
//    self.emptyLabel.hidden = self.displayMemos.count > 0;
    self.emptyLabel.hidden = YES;
    self.emptyLabel.text = self.searchBar.text.length > 0 ? @"No search results" : @"No files";
    self.addButton.hidden = (self.displayMemos.count > 0 || self.searchBar.text.length > 0);
}

- (void)handleMemoUpdate {

    [self loadData];
}

#pragma mark - Actions
- (void)addNewMemo {
    MemoEditViewController *editVC = [[MemoEditViewController alloc] init];
    UINavigationController *nav = [[UINavigationController alloc] initWithRootViewController:editVC];
    nav.modalPresentationStyle = UIModalPresentationFullScreen;
    [self presentViewController:nav animated:YES completion:nil];
}

- (void)toggleEditMode {
    self.isEditingMode = !self.isEditingMode;
//    self.navigationItem.leftBarButtonItem.title = self.isEditingMode ? @"完成" : @"编辑";
    [self.collectionView reloadData];
}

- (void)deleteMemo:(UIButton *)sender {

    UIAlertController *alert = [UIAlertController alertControllerWithTitle:@"Delete"
                                                                   message:@"This record will be permanently deleted"
                                                            preferredStyle:UIAlertControllerStyleAlert];
    [alert addAction:[UIAlertAction actionWithTitle:@"Cancel" style:UIAlertActionStyleDefault handler:^(UIAlertAction * _Nonnull action){
        [self cancelButtonTapped];
    }]];
    [alert addAction:[UIAlertAction actionWithTitle:@"Delete" style:UIAlertActionStyleDestructive handler:^(UIAlertAction * _Nonnull action){
        [self deleteButtonTapped:sender.tag];
    }]];
    [self presentViewController:alert animated:YES completion:nil];


}

- (void)deleteButtonTapped:(NSInteger)tag {
    NSInteger index = tag;
    if (index < self.displayMemos.count) {
        MemoModel *memo = self.displayMemos[index];
        [MemoModel deleteMemo:memo.memoId];
        [self loadData];

        [self dismissViewControllerAnimated:YES completion:nil];
    }
}

- (void)cancelButtonTapped{
    [self dismissViewControllerAnimated:YES completion:nil];
}

