- (void)startSnapshotTimer { // 每一秒记录一次当前文本
    self.snapshots = [NSMutableArray array];
    self.snapshotTimer = [NSTimer scheduledTimerWithTimeInterval:1.0
                                                          target:self
                                                        selector:@selector(captureSnapshot)
                                                        userInfo:nil
                                                         repeats:YES];
}

#pragma mark - 手势处理
- (void)handleTap:(UITapGestureRecognizer *)gesture {
    // 获取点击位置
    CGPoint location = [gesture locationInView:self.view];

    // 检查是否点击在输入框之外
    BOOL isOutsideTitleField = !CGRectContainsPoint(self.titleTextField.frame, location);
    BOOL isOutsideTextView = !CGRectContainsPoint(self.contentTextView.frame, location);

    if (isOutsideTitleField && isOutsideTextView) {
        // 点击在输入框之外的空白区域，关闭键盘
        [self.view endEditing:YES];
    }
}

