#pragma mark - AudioSession For Speech

//初始化音频相关内容
- (void)setupAudioSessionForSpeech {
    self.speedOptions = @[@"0.5X", @"1X", @"1.25X", @"1.5X", @"2X", @"3X"];     // 初始化倍速选项
    self.selectedSpeed = 1.0;  // 默认倍速为1倍速

    // AVAudioSession——配置和管理音频行为的核心类，适用于音频播放和录制的各种需求
    AVAudioSession *audioSession = [AVAudioSession sharedInstance];
    // 这里设置 AVAudioSessionCategoryPlayback 类别，使应用能在后台或静音模式下进行音频播放
    NSError *Error = nil;
    [audioSession setCategory:AVAudioSessionCategoryPlayback error:&Error];
    if (Error) {
        NSLog(@"音频会话设置出错: %@", Error);
    }
    // setActive:YES 将音频会话激活，使设置生效并确保音频会话处于活跃状态。这一步通常在应用准备播放或录制音频时执行。激活后，音频会话将控制系统音频资源，避免与其他应用冲突。
    Error = nil;
    [audioSession setActive:YES error:&Error];
    if (Error) {
        NSLog(@"音频会话激活出错: %@", Error);
    }

    // 初始化AVSpeechSynthesizer
    self.speechSynthesizer = [[AVSpeechSynthesizer alloc] init];
    self.speechSynthesizer.delegate = self;

    // 初始化AVSpeechUtterance
    self.utterance = [[AVSpeechUtterance alloc] initWithString:@" "];
    self.utterance.voice = [AVSpeechSynthesisVoice voiceWithIdentifier:@"com.apple.voice.compact.zh-CN.Tingting"];
    self.utterance.rate = self.selectedSpeed*0.5;  // 根据选择的倍速播放，注意在rate的取值范围是[0,1],默认为0.5是正常语速，需要将selectedSpeed做一个转化

    // 第一次朗读会有延迟问题，在页面加载但还未显示时就先朗读一次空格文本，当用户使用时就不会出现延迟
    [self.speechSynthesizer speakUtterance:self.utterance];
}

#pragma mark - Play UIEvent

- (void)startPlay:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2]; // 决定动画的复杂程度或效果
    NSString *textToSpeak = self.inputTextView.text;
    if (textToSpeak.length > 0 && textToSpeak.length < 3000) {
        // 检查当前是否正在播放音频
        // 正在播放
        if (self.speechSynthesizer.isSpeaking) {
            // 停止播放并将按钮恢复到初始状态
            [self.speechSynthesizer stopSpeakingAtBoundary:AVSpeechBoundaryImmediate];
            [self updateButtonsState];
        // 没有播放
        }else{
            self.utterance= [[AVSpeechUtterance alloc] initWithString:textToSpeak];
            self.utterance.rate = self.selectedSpeed * 0.5;
            [self.speechSynthesizer speakUtterance:self.utterance];
            [self updateButtonsState];
            _speedButton.enabled = NO;
            _speedButton.backgroundColor = WHITE_COLOR;
            [self.speedButton setTitleColor:self.speedButton.enabled ? WHITE_COLOR : BLACK_COLOR forState:UIControlStateNormal];
            [self.startButton setTitle:@"暂停" forState:UIControlStateNormal];
        }

    }
}

// 文本播放完毕时调用
- (void)speechSynthesizer:(AVSpeechSynthesizer *)synthesizer didFinishSpeechUtterance:(AVSpeechUtterance *)utterance {
    // 自动恢复按钮状态
    [self updateButtonsState];
}

- (void)updateButtonsState {
    BOOL hasText = self.inputTextView.text.length > 0;
    UIColor *disabledColor = WHITE_COLOR; // 灰色不可点击状态
    UIColor *enabledColor = DEEP_COLOR_1;

    // 输入框有内容且未播放时才启用倍速按钮
    BOOL isPlaying = self.speechSynthesizer.speaking;
    self.speedButton.enabled = hasText && !isPlaying;
    self.speedButton.backgroundColor = self.speedButton.enabled ? enabledColor : disabledColor;
    [self.speedButton setTitleColor:self.speedButton.enabled ? WHITE_COLOR : BLACK_COLOR forState:UIControlStateNormal];

    // 开始按钮始终在输入框有内容时可点击
    self.startButton.enabled = hasText;
    self.startButton.backgroundColor = hasText ? enabledColor : disabledColor;
    [self.startButton setTitleColor:hasText ? WHITE_COLOR : BLACK_COLOR forState:UIControlStateNormal];


    // 播放状态更新暂停按钮文字
    if (isPlaying) {
        [self.startButton setTitle:@"暂停" forState:UIControlStateNormal];
    } else {
        [self.startButton setTitle:@"播放" forState:UIControlStateNormal];
    }
}
#pragma mark - Speed UIEvent

//播放完全由startPlay实现，speedButton主要是选择倍速的ui效果
- (void)speedPlay:(UIButton *)sender {
    [sender showClickedAnimationWithLevel:2];
    if (self.speedCollectionView.isHidden) {
        [self showSpeedSelection];
        _speedButton.alpha = 1.0;
    } else {
        [self hideSpeedSelection];
    }
}

// 显示倍速选择
- (void)showSpeedSelection {
    self.dimmedBackgroundView.hidden = NO;
    self.speedCollectionView.hidden = NO;
    [UIView animateWithDuration:0.3 animations:^{
        self.dimmedBackgroundView.alpha = 0.5;  // 背景变暗
    }];
}

// 隐藏倍速选择
- (void)hideSpeedSelection {
    [UIView animateWithDuration:0.3 animations:^{
        self.dimmedBackgroundView.alpha = 0.0;  // 背景恢复透明

    } completion:^(BOOL finished) {
        self.dimmedBackgroundView.hidden = YES;
        self.speedCollectionView.hidden = YES;
    }];
}

#pragma mark - Keyboard UIEvent

// 键盘按 return 关闭键盘
- (BOOL)textView:(UITextView *)textView shouldChangeTextInRange:(NSRange)range replacementText:(NSString *)text {
    // 检查是否是inputTextView
    if (textView == self.inputTextView) {
        if ([text isEqualToString:@"\n"]) { // 检查是否是"Return"键
            // 隐藏键盘
            [textView resignFirstResponder];
            return NO; // 取消文本框的换行
        }
    }
    return YES; // 允许文本的更改
}

// 点击空白处关闭键盘
- (void)touchesBegan:(NSSet<UITouch *> *)touches withEvent:(UIEvent *)event {
    [self.view endEditing:YES]; // 关闭键盘
}

#pragma mark - UITextView 动态处理

// 处理 UITextView 的文本变化
- (void)textViewDidChange:(UITextView *)textView {
    // 动态调整输入框的高度
    [self adjustTextViewHeight];
    [self placeholderDidChange:textView];
    [self updateButtonsState];
}

// 动态调整 UITextView 高度
- (void)adjustTextViewHeight {
    //NSLog(@"最大文本框高度: %f", self.maxTextViewHeight);
    CGSize sizeThatFitsTextView = [self.inputTextView sizeThatFits:CGSizeMake(self.inputTextView.frame.size.width, MAXFLOAT)];
    CGFloat newHeight = MIN(sizeThatFitsTextView.height, self.maxTextViewHeight);
    newHeight = MAX(newHeight, self.minTextViewHeight); // 确保不小于初始高度
    [self.inputTextView mas_updateConstraints:^(MASConstraintMaker *make) {
        make.height.mas_equalTo(newHeight);
    }];
    self.inputTextView.scrollEnabled = sizeThatFitsTextView.height > newHeight;
}

