#pragma mark - UICollectionView

// UICollectionView DataSource
- (NSInteger)collectionView:(UICollectionView *)collectionView numberOfItemsInSection:(NSInteger)section {
    return self.speedOptions.count;
}

// DataSource 方法
- (SpeedCell *)collectionView:(UICollectionView *)collectionView cellForItemAtIndexPath:(NSIndexPath *)indexPath {
    SpeedCell *cell = [collectionView dequeueReusableCellWithReuseIdentifier:@"SpeedCell" forIndexPath:indexPath];
    // 根据 indexPath 设置标签的文本
    cell.speedLabel.text = self.speedOptions[indexPath.item]; // 设置倍速标签内容
    cell.speedLabel.textColor = BLACK_COLOR; // 默认颜色
    cell.backgroundColor = WHITE_COLOR; // 默认背景颜色
//    cell.layer.cornerRadius = 5.0;
//    cell.layer.borderColor=DEEP_COLOR.CGColor;
//    cell.layer.borderWidth = 1.0; // 边框宽度
    cell.layer.cornerRadius = ZOOM(21);
    cell.layer.masksToBounds = YES;
//    cell.contentView.layer.cornerRadius = ZOOM(21);
//    cell.contentView.layer.masksToBounds = YES;
    return cell;
}

// 设置 cell 的大小
- (CGSize)collectionView:(UICollectionView *)collectionView layout:(UICollectionViewLayout *)collectionViewLayout sizeForItemAtIndexPath:(NSIndexPath *)indexPath {
    CGFloat collectionViewWidth = collectionView.frame.size.width;
    CGFloat collectionViewHeight=collectionView.frame.size.height;
    // 设置 cell 的宽度和高度
    CGFloat itemWidth = (collectionViewWidth - ZOOMW(40)) / 3; // 每行三个 cell，留出边距
    CGFloat itemHeight = (collectionViewHeight - ZOOM(30)) / 2; // 每行两个 cell，留出边距
    return CGSizeMake(itemWidth, itemHeight);
}

// UICollectionView Delegate
- (void)collectionView:(UICollectionView *)collectionView didSelectItemAtIndexPath:(NSIndexPath *)indexPath {
    NSString *selectedSpeedString = self.speedOptions[indexPath.item];
    self.selectedSpeed = [[selectedSpeedString stringByReplacingOccurrencesOfString:@"X" withString:@""] floatValue];
    // 取消之前选择的 cell 的选中效果
    for (NSIndexPath *visibleIndexPath in [collectionView indexPathsForVisibleItems]) {
        SpeedCell *cell = (SpeedCell *)[collectionView cellForItemAtIndexPath:visibleIndexPath];
        cell.backgroundColor = WHITE_COLOR; // 恢复默认背景颜色
        cell.speedLabel.textColor = BLACK_COLOR; // 恢复默认字体颜色
    }
    // 获取当前选择的 cell
    SpeedCell *selectedCell = (SpeedCell *)[collectionView cellForItemAtIndexPath:indexPath];
    selectedCell.backgroundColor = RGBA(41, 123, 255, 1); // 设置选中时的背景颜色
    selectedCell.speedLabel.textColor = WHITE_COLOR; // 将选中标签的颜色改为白色
    // 更新倍速按钮标题
    [self.speedButton setTitle:selectedSpeedString forState:UIControlStateNormal];
}

