- (UIView *)dimmedBackgroundView {
    if (!_dimmedBackgroundView) {
        _dimmedBackgroundView = [[UIView alloc] init];
        _dimmedBackgroundView.backgroundColor = [UIColor blackColor];
        _dimmedBackgroundView.alpha = 0.0;  // 初始透明
        _dimmedBackgroundView.hidden = YES; // 确保默认情况下是隐藏的
        UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:self action:@selector(hideSpeedSelection)];
        [_dimmedBackgroundView addGestureRecognizer:tapGesture]; // 添加点击手势识别器
    }
    return _dimmedBackgroundView;
}

- (UICollectionView *)speedCollectionView {
    if (!_speedCollectionView) {
        UICollectionViewFlowLayout *layout = [[UICollectionViewFlowLayout alloc] init];
        layout.minimumLineSpacing = ZOOMW(10);  // 行间距
        layout.minimumInteritemSpacing = ZOOM(10); // 列间距
        // 使用动态计算的 itemSize
        _speedCollectionView.scrollEnabled=NO;
        _speedCollectionView = [[UICollectionView alloc] initWithFrame:CGRectZero collectionViewLayout:layout];
        _speedCollectionView.delegate = self;
        _speedCollectionView.dataSource = self;
        _speedCollectionView.backgroundColor = RGBA(227, 228, 231, 1);
        _speedCollectionView.layer.cornerRadius = ZOOM(8); // 圆角
        [_speedCollectionView registerClass:[SpeedCell class] forCellWithReuseIdentifier:@"SpeedCell"];
        _speedCollectionView.hidden = YES; // 确保默认情况下是隐藏的
        // 设置sectionInset，即cell到collectionView边框的距离
        layout.sectionInset = UIEdgeInsetsMake(ZOOM(10), ZOOMW(10), ZOOM(10), ZOOMW(10));
    }
    return _speedCollectionView;
}

