    [cell.accessary removeTarget:nil action:nil forControlEvents:UIControlEventTouchUpInside];

    cell.nameLabel.text = _cellTitles[indexPath.item];
    if (indexPath.item == 0) {
        cell.contentLabel.hidden = NO;
