        formatter.dateFormat = @"yyyy-MM-dd"; // 自定义格式
        NSString *dateString = [formatter stringFromDate:self.selectedDate];

        cell.contentLabel.text = dateString;
    }else if (indexPath.item == 1) {
        cell.contentLabel.hidden = NO;
        cell.accessary.hidden = NO;
        cell.contentImage.hidden = YES;
        cell.Switch.hidden = YES;

        [cell.accessary addTarget:self action:@selector(showendDatePicker:) forControlEvents:UIControlEventTouchUpInside];

        NSDateFormatter *formatter = [[NSDateFormatter alloc] init];
        formatter.dateFormat = @"yyyy-MM-dd"; // 自定义格式
