    NSString *lastTitle = latestSnapshot[@"title"];
    NSString *lastContent = latestSnapshot[@"content"];

    // ⚠️ 只有当标题或内容有变化时才保存
    if (![currentTitle isEqualToString:lastTitle] ||
        ![currentContent isEqualToString:lastContent]) {

        NSDictionary *snapshot = @{
            @"title": currentTitle,
