- (NSString *)saveImageToLocalPath:(UIImage *)image {
    if (!image) { return @""; }
    NSData *imageData = UIImageJPEGRepresentation(image, 0.85);
    if (imageData.length == 0) { return @""; }
    NSString *directory = [ServiceMsgModel imageDirectoryPath];
    NSError *directoryError = nil;
    if (![[NSFileManager defaultManager] fileExistsAtPath:directory]) {
        [[NSFileManager defaultManager] createDirectoryAtPath:directory
                                  withIntermediateDirectories:YES
                                                   attributes:nil
                                                        error:&directoryError];
    }
    if (directoryError) { return @""; }
    NSString *fileName = [NSString stringWithFormat:@"service_%@.jpg", NSUUID.UUID.UUIDString];
    NSString *filePath = [directory stringByAppendingPathComponent:fileName];
    NSError *writeError = nil;
    BOOL success = [imageData writeToFile:filePath options:NSDataWritingAtomic error:&writeError];
    if (!success || writeError) { return @""; }
    return filePath;
}

