#import "ServiceMsgCell.h"


@implementation ServiceMsgCell

- (instancetype)initWithStyle:(UITableViewCellStyle)style reuseIdentifier:(NSString *)identifier {
    self = [super initWithStyle:style reuseIdentifier:identifier];
    if (self) {
        [self setupSubviews];
        // 隐藏单元格底部的分割线
        self.backgroundColor=CLEAR_COLOR;
        self.separatorInset = UIEdgeInsetsMake(0, CGRectGetMaxX(self.contentView.frame) + 1000, 0, 0);
        // 设置被选中时背景不发生变化
        self.selectionStyle = UITableViewCellSelectionStyleNone;
        self.messageLabel.userInteractionEnabled = YES;
        UILongPressGestureRecognizer *longPressGesture = [[UILongPressGestureRecognizer alloc] initWithTarget:self action:@selector(handleLongPress:)];
        [self.messageLabel addGestureRecognizer:longPressGesture];
    }
    return self;
}

- (void)handleLongPress:(UILongPressGestureRecognizer *)gestureRecognizer {
    if (gestureRecognizer.state == UIGestureRecognizerStateBegan) {
        [self setSelected:NO animated:NO];
        // 获取长按的位置
        CGPoint location = [gestureRecognizer locationInView:self.messageLabel];
        [self.messageLabel becomeFirstResponder];
        [self showMenuAtLocation:location];
    }
}

- (void)showMenuAtLocation:(CGPoint)location{
    UIMenuController *menuController = [UIMenuController sharedMenuController];
    UIMenuItem *copyItem = [[UIMenuItem alloc] initWithTitle:@"Copy" action:@selector(copyText:)];
    menuController.menuItems = @[copyItem];
    // 获取相对于 messageLabel 的目标矩形
    CGRect targetRect = CGRectMake(location.x, location.y, 1, 1);
    // 显示菜单
    [menuController showMenuFromView:self.messageLabel rect:targetRect];
}

- (void)copyText:(id)sender {
    UIPasteboard *pasteboard = [UIPasteboard generalPasteboard];
    pasteboard.string = self.messageLabel.text;
    // 显示成功的弹窗
    [UIView showHUDWithStatus:@"Copied" imageName:@"Success"];
}

- (void)setSelected:(BOOL)selected animated:(BOOL)animated {
    // 不调用父类方法，避免选中状态
}

#pragma mark - Setup Subviews

- (void)setupSubviews {
    // 初始化各组件
    _avatarImageView = [[UIImageView alloc] init];
    _messageLabel = [[UILabel alloc] init];
    _bubbleView = [[UIView alloc] init];
    _messageImageView = [[UIImageView alloc] init];
    _avatarImageView.contentMode = UIViewContentModeScaleAspectFill;
    // 设置气泡布局
    [_bubbleView.layer setCornerRadius:ZOOM(12)];
    _bubbleView.layer.masksToBounds = YES;
    // 设置消息标签样式
    _messageLabel.numberOfLines = 0;
    _messageLabel.lineBreakMode = NSLineBreakByCharWrapping;
    _messageLabel.textAlignment = NSTextAlignmentLeft;
    _messageLabel.font=[UIFont systemFontOfSize:16.0];
    _messageImageView.contentMode = UIViewContentModeScaleAspectFill;
    _messageImageView.clipsToBounds = YES;
    _messageImageView.hidden = YES;
    // 设置时间戳样式
    // 将子视图添加到cell的内容视图中
    [self.contentView addSubview:_avatarImageView];
    [self.contentView addSubview:_bubbleView];
    [self.bubbleView addSubview:_messageLabel];
    [self.bubbleView addSubview:_messageImageView];
    // 消息标签约束
    [_messageLabel mas_makeConstraints:^(MASConstraintMaker *make) {
        make.top.equalTo(self.bubbleView).offset(ZOOM(10));
        make.left.equalTo(self.bubbleView).offset(ZOOMW(10));
        make.right.equalTo(self.bubbleView).offset(-ZOOMW(10));
        make.bottom.equalTo(self.bubbleView).offset(-ZOOM(10));
    }];
}

#pragma mark - Prepare for Reuse

// 当单元格被复用时，清除旧的数据，确保每次展示都是最新的内容
- (void)prepareForReuse {
    [super prepareForReuse];
    // 清除旧数据
    _avatarImageView.image = nil;
    _messageLabel.text = @"";
    _messageLabel.hidden = NO;
    _messageImageView.image = nil;
    _messageImageView.hidden = YES;
}

- (CGSize)displaySizeForImageSize:(CGSize)imageSize {
    CGFloat ratio = (imageSize.height > 0.0f) ? (imageSize.width / imageSize.height) : 0.0f;
    CGFloat fixedWidth = (ratio > 1.0f) ? ZOOMW(220) : ZOOMW(160);
    CGFloat maxWidth = [UIScreen mainScreen].bounds.size.width * 0.72f;
    CGFloat width = (ratio > 0.0f) ? MIN(fixedWidth, maxWidth) : ZOOMW(160);
    CGFloat height = (ratio > 0.0f) ? (width / ratio) : ZOOMW(180);
    return CGSizeMake(width, height);
}

- (void)updateBubbleConstraintsForType:(MessageTypeS)type {
    if (type == MessageTypeUser) {
        [_avatarImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.contentView).offset(ZOOM(10));
            make.width.height.mas_equalTo(ZOOM(44));
            make.right.equalTo(self.contentView).offset(ZOOMW(-16));
        }];
        [_bubbleView mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.contentView).offset(ZOOM(10));
            make.bottom.equalTo(self.contentView).offset(ZOOM(-10));
            make.width.lessThanOrEqualTo(@(ZOOMW(280)));
            make.right.equalTo(self.avatarImageView.mas_left).offset(ZOOMW(-16));
        }];
    } else {
        [_avatarImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.contentView).offset(ZOOM(10));
            make.width.height.mas_equalTo(ZOOM(44));
            make.left.equalTo(self.contentView).offset(ZOOMW(16));
        }];
        [_bubbleView mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.contentView).offset(ZOOM(10));
            make.bottom.equalTo(self.contentView).offset(ZOOM(-10));
            make.width.lessThanOrEqualTo(@(ZOOMW(280)));
            make.left.equalTo(self.avatarImageView.mas_right).offset(ZOOMW(10));
        }];
    }
}

#pragma mark - Configure Send and Receive Cell

// 注意：由于出现单元格复用的情况，所以约束使用mas_remakeConstraints而非mas_makeConstraints和mas_updateConstraints
- (void)configureWithMessage:(ServiceMsgModel *)message iconSendImage:(UIImage*)sicon iconReceiveImage:(UIImage*)ricon{
    if (message.type == MessageTypeUser) {
        self.type = MessageTypeUser;
        self.bubbleView.backgroundColor = USER_BUBBLEVIEW;
        self.messageLabel.textColor = USER_TEXT;
        self.avatarImageView.image = sicon;
        self.avatarImageView.hidden = NO;
    } else {
        self.type = MessageTypeService;
        self.bubbleView.backgroundColor = SERVICE_BUBBLEVIEW;
        self.messageLabel.textColor = SERVICE_TEXT;
        self.avatarImageView.image = ricon;
        self.avatarImageView.hidden = NO;
    }
    [self updateBubbleConstraintsForType:message.type];

    if (message.contentType == ServiceMsgContentTypeImage) {
        self.messageLabel.hidden = YES;
        self.messageImageView.hidden = NO;
        UIImage *image = [UIImage imageWithContentsOfFile:[message resolvedImagePath]];
        self.messageImageView.image = image;
        CGSize displaySize = [self displaySizeForImageSize:CGSizeMake(message.imageWidth, message.imageHeight)];
        [self.messageImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.bubbleView).offset(ZOOM(6));
            make.left.equalTo(self.bubbleView).offset(ZOOM(6));
            make.right.equalTo(self.bubbleView).offset(-ZOOM(6));
            make.bottom.equalTo(self.bubbleView).offset(-ZOOM(6));
            make.size.mas_equalTo(displaySize);
        }];
        [self.messageLabel mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.size.mas_equalTo(CGSizeZero);
        }];
    } else {
        self.messageLabel.hidden = NO;
        self.messageImageView.hidden = YES;
        [self.messageLabel mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.top.equalTo(self.bubbleView).offset(ZOOM(10));
            make.left.equalTo(self.bubbleView).offset(ZOOMW(10));
            make.right.equalTo(self.bubbleView).offset(-ZOOMW(10));
            make.bottom.equalTo(self.bubbleView).offset(-ZOOM(10));
        }];
        [self.messageImageView mas_remakeConstraints:^(MASConstraintMaker *make) {
            make.size.mas_equalTo(CGSizeZero);
        }];
        self.messageLabel.text = message.content ?: @"";
    }
}


@end

